CREATE VIEW results.v_vasopressors_nee AS SELECT d.person_id, d.drug_exposure_start_datetime, d.drug_concept_id, d.quantity, CASE d.drug_concept_id WHEN 4328749 THEN 1.0 WHEN 1338005 THEN 1.0 WHEN 1360635 THEN 2.5 WHEN 1335616 THEN 0.1 WHEN 1319998 THEN 0.01 END AS nee_factor, CASE d.drug_concept_id WHEN 1360635 THEN TRUE ELSE FALSE END AS is_vasopressin FROM cdm.drug_exposure d WHERE d.drug_concept_id IN (4328749,1338005,1360635,1335616,1319998);